import{_ as l,N as t,o as i,a as r,e as o,i as n}from"./chunks/framework.DW6Cm6Mn.js";const _=JSON.parse('{"title":"О Vala","description":"Vala - это объектно-ориентированный язык программирования с самодостаточным компилятором, который генерирует код Cи и использует систему типов GObject.","frontmatter":{"title":"О Vala","description":"Vala - это объектно-ориентированный язык программирования с самодостаточным компилятором, который генерирует код Cи и использует систему типов GObject."},"headers":[],"relativePath":"ru/about/index.md","filePath":"ru/about/index.md"}'),d={name:"ru/about/index.md"};function h(c,a,s,p,u,V){const e=t("PredefinedCtaStack");return i(),r("div",null,[a[0]||(a[0]=o('<h1 id="о-vala" tabindex="-1">О Vala <a class="header-anchor" href="#о-vala" aria-label="Permalink to &quot;О Vala&quot;">​</a></h1><h2 id="что-такое-vala" tabindex="-1">Что такое Vala? <a class="header-anchor" href="#что-такое-vala" aria-label="Permalink to &quot;Что такое Vala?&quot;">​</a></h2><p>Vala - это объектно-ориентированный язык программирования с самодостаточным компилятором, который генерирует код Cи и использует систему типов GObject.</p><p>Vala поддерживает современные языковые функции, такие как:</p><ul><li>Интерфейсы</li><li>Свойства</li><li>Сигналы</li><li>Foreach</li><li>Лямбда-выражения</li><li>Вывод типа для локальных переменных</li><li>Дженерики</li><li>Ненулевые типы</li><li>Лёгкое управление памятью</li><li>Обработка исключений</li><li>Типы модулей (плагины)</li></ul><h2 id="почему-vala" tabindex="-1">Почему Vala? <a class="header-anchor" href="#почему-vala" aria-label="Permalink to &quot;Почему Vala?&quot;">​</a></h2><h3 id="производительныи" tabindex="-1">Производительный <a class="header-anchor" href="#производительныи" aria-label="Permalink to &quot;Производительный&quot;">​</a></h3><p>С Vala вы можете быстро приступить к работе благодаря таким удобным функциям, как лямбда-выражения, обработка исключений, интерфейсы и дженерики.</p><h3 id="быстрыи" tabindex="-1">Быстрый <a class="header-anchor" href="#быстрыи" aria-label="Permalink to &quot;Быстрый&quot;">​</a></h3><p>Код Vala компилируется в полностью нативные двоичные файлы.</p><h3 id="статически-типизированныи" tabindex="-1">Статически типизированный <a class="header-anchor" href="#статически-типизированныи" aria-label="Permalink to &quot;Статически типизированный&quot;">​</a></h3><p>Vala помогает вам писать безопасный код без хлопот, благодаря выводу типов.</p><h3 id="интегрированныи" tabindex="-1">Интегрированный <a class="header-anchor" href="#интегрированныи" aria-label="Permalink to &quot;Интегрированный&quot;">​</a></h3><p>Vala предназначен для обеспечения доступа к существующим библиотекам Cи, особенно к библиотекам на основе GObject, без необходимости привязок во время выполнения. Все, что необходимо для использования библиотеки Vala - это файл API, содержащий объявления классов и методов в синтаксисе Vala. В настоящее время Vala поставляется с привязками для GLib и GTK+ и многими другими библиотеками с платформы GNOME.</p><p>Vala также можно использовать для создания библиотек языка Си.</p><h3 id="знакомыи" tabindex="-1">Знакомый <a class="header-anchor" href="#знакомыи" aria-label="Permalink to &quot;Знакомый&quot;">​</a></h3><p>Синтаксис Vala вдохновлен C# и Java, поэтому, если вы использовали любой из них, вы с легкостью адаптируетесь к написанию кода на Vala.</p>',17)),n(e)])}const m=l(d,[["render",h]]);export{_ as __pageData,m as default};
